const Q_CHEMISTRY_2008=[{"id": "objective>Chemistry>2008>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorophyll obtained from green leaves of plant can be composed of more than one coloured component by the technique of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chromatography</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorophyll obtained from green leaves of plants can be separated into its different coloured components using the technique of chromatography. Chromatography is a method used to separate the different components in a mixture based on their different affinities for a stationary and a mobile phase.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2008>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In countries where the temperature falls below 273 K, salt is always sprinkled on the icy roads in order to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lower the melting point of the ice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the density of the ice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">make the ice impure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">raise the melting point of the ice</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In countries where the temperature falls below 273 K, salt is sprinkled on icy roads to lower the melting point of the ice. This is because salt, when mixed with ice, causes a decrease in the freezing point of water, causing the ice to melt at a lower temperature.</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2008>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(l)</span> ⇒ 2NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/>  From the equation above, calculate the mass of sodium hydroxide produced by 2.3g of sodium</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.40g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.80g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.00g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.00g</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l) </span> → 2NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  Molar mass of NaOH = (1 x 23) + (1 x 16) + (1 x 1) <br/> =23+16+1=40g/mol  <br/> Molar mass of Na = (1 x 23) = 23g/mol <br/> From the equation above, 2 moles of Na produced 2 moles of NaOH <br/> 2.3g of Na will produce Xg of NaOH <br/> But mass of 2 moles of Na = Mole x Molar mass of Na <br/> =2 x 23 <br/> =46g <br/> Also Mass of 2 moles of NaOH= mole x molarmass of NaOH=2 x 40= 80g <br/> Therefore, <br/> 46g of Na produced 80g of NaOH <br/> 2.3g of sodium will produce Xg of NaOH <br/> X=(2.3 x 80)/46 <br/> =184/46 <br/> =4.00g of NaOH</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2008>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">16.8g of sodium hydrogen trioxocarbonate(IV) is completely decomposed by heat. Calculate the volume of carbon(IV) oxide given off at s.t.p.  <br/> [Na = 23, C = 12, O = 16, H = 1, Molar volume of gas at s.t.p. = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">22.40dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.20dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.24dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.12dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> ⇒ Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  <br/> Molarmass of NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/>  <br/> = (1 × 23) + (1 × 1) + (1 × 12) + (3 x 16) <br/>  = 23 + 1 + 12 + 48 <br/> = 84g/mol <br/> From the equation above, <br/> 2 moles of NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> liberated 1 mole of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> at s.t.p <br/> 16.8g of NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> will liberate Xdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> at s.t.p <br/>  <br/> But 1 mole of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> at s.t.p = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> Mass of 2 moles of NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = mole × molarmass <br/> = 2 × 84 <br/> = 168g <br/> Therefore <br/>  <br/> 168g NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> will liberate 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> at s.t.p <br/> 16.8g of NaHCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> will liberate Xdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p <br/> X =  (16.8 × 22.4)/(168)  <br/>    = 2.24dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2008>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">300 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a gas has a pressure of 800mm Hg. If the pressure is reduced to 650mm Hg, find its volume.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">243.75 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">369.23 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">738.46 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1733.36 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 300cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>= 800mmHg, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= 650mmHg  <br/>  P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> , V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= 800 × 300/650 = 369.23cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>2008>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion is slowest in solid particles than in particles of liquids and gases because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">solid particles have more kinetic energy than the particles of liquids and gases.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid particles have less kinetic energy than the particles of liquids and gases.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid particles have less restrictions in their movement than liquid and gas particles.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the particles in solids are far apart and the cohesive forces between them are negligible.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diffusion is the process of particles spreading out from an area of high concentration to an area of low concentration. In solids, the particles are closely packed together and have less kinetic energy, which means they move less and therefore diffuse more slowly. In contrast, particles in liquids and gases have more kinetic energy and can move more freely, resulting in faster diffusion. Therefore, the correct answer is that solid particles have less kinetic energy than the particles of liquids and gases.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2008>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The experiment that showed that atoms have tiny positively charged nucleus was first carried out by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Moseley </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Rutherford</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Millikan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dalton</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The experiment that demonstrated the existence of a small, positively charged nucleus in atoms was conducted by Ernest Rutherford. This experiment, known as the gold foil experiment, involved firing alpha particles at a thin sheet of gold. Most of the alpha particles passed straight through the gold foil, but some were deflected at large angles. This led Rutherford to conclude that the positive charge in an atom is concentrated in a small area in the center of the atom, which he called the nucleus. Therefore, the correct answer is Rutherford.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2008>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The atom of an element X is represented as <span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">Y</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">Z</span>X The basic chemical properties of X depend on the value of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Y </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y - Z </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z - Y</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basic chemical properties of an element are determined by the number of electrons in the outermost shell of its atom. This is represented by the atomic number (Z) of the element. Therefore, the basic chemical properties of X depend on the value of Z.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2008>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The diagram above represents the electron sub-level for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluorine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The number of arrows indicate the number of electron. Since atomic number of oxygen is 8, the element is oxygen.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2008>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the Periodic Table, electrical and thermal conductivities are properties of elements that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease across the period and increase down the group.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase across the period and decrease down the group.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease across the period and down the group.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase across the period and down the group.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the periodic table electrical and thermal conductivities of elements decrease across the period and increase down the group.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2008>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The reaction above is an example of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nuclear fission </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nuclear fusion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">artificial transmutation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">beta decay</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Artificial transmutation. It is an artificially induced nuclear reaction caused by the bombardment of a nucleus with subatomic particiles or small nucei. It is also called artififcial radioactivity.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2008>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Air boiled out of water as steam is richer in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrogen and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide and oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">noble gases and carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen and noble gases</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Air boiled out of water as steam is richer in carbon(IV)oxide and oxygen.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2008>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the course of purifying water for town supply, the water is passed through large settling tanks containing sodium aluminate (III) to remove</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Large particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">germs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fine particles </div>", "<div style=\"font-family:Cambria;font-size:17px;\">odour</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the course of purifying water for town supply, the water is passed through large settling tanks containing sodium aluminate (III) to remove fine particles. Sodium aluminate (III) acts as a coagulant, causing fine particles to clump together and settle to the bottom of the tank.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2008>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a few drops of water is added to a blue anhydrous cobalt (II) chloride, the <br/> colour changes to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">white </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pink </div>", "<div style=\"font-family:Cambria;font-size:17px;\">red </div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a few drops of water is added to a blue anhydrous cobalt (II) chloride, the colour changes to pink. This is because cobalt (II) chloride is a hydrate, and when water is added, it forms a pink hydrated compound.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2008>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The Vulcanizer's solution is prepared by dissolving rubber in</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">kerosene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">benzene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">petrol</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Vulcanizer's solution is prepared by dissolving rubber in benzene. Benzene is a good solvent for many organic compounds and is used to dissolve and extract substances from plants and animals.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2008>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">117.0g of sodium chloride was dissolved in 1.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of distilled water at <br/> 25°C. Determine the solubility in moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of sodium chloride at that temperature.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.0 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> mass of the salt = 117.0g <br/> Since the salt given is sodium chloride, the molar mass is 58.5gmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> number of mole = 117/58.5 = 2.0 mol <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Solubility</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.0mol<hr size=\"1\" />1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2.0</td><td style=\"text-align:center;\">moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></td></tr></table></div></div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2008>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The uncovered raw food that is sold along major roads is likely to contain some amounts of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pb </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ag </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lead (Pb) is a common pollutant found in the environment, especially in areas with heavy traffic. It can be released into the air from the exhaust of vehicles and can contaminate food sold along major roads.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2008>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the pH of a 0.001 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> solution of sodium hydroxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">13 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">11</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">[H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>][OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>]= 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>  <br/>  [H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>]= 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>/[OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>]= 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-14</span>/(1 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>)= 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>  <br/>  PH= -log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>[H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>]= -log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>[10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>]= -1 × -11log<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">10</span>10 = 11</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2008>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basicity of CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basicity of an acid refers to the number of hydrogen ions (H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) it can donate. Acetic acid (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH) can donate one hydrogen ion, so its basicity is 1.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2008>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">0.05 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> HCl is neutralized by 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> NaOH. If the volume of acid used is 32.00 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, what is the concentration of the base?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.016 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.032 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.039 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.064 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">HCl + NaOH → NaCl + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O  <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span> = N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>/N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>  <br/>  N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>= 1, N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>= 1, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>= 0.05, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">A</span>= 32.00cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>= ?, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>= 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">B</span>= 0.05 × 32/25= 0.064moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2008>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Insoluble salts can be prepared by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">titrating an alkali against an appropriate acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reacting an acid with trioxocarbonate (IV) salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct combination of the elements which make up the salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mixing two soluble compounds containing the metallic radical and the acidic radical</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Insoluble salts can be prepared by mixing two soluble compounds containing the metallic radical and the acidic radical. This is known as a precipitation reaction, where two soluble salts react to form an insoluble salt (precipitate) and a soluble salt.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2008>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation state of carbon in HCOOH is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">–1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+2 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">+3 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation state of carbon in HCOOH (formic acid) is +2. This is calculated by assigning oxidation states to each atom in the molecule: hydrogen is +1, oxygen is -2, and the sum of the oxidation states in a neutral molecule is zero. Therefore, the oxidation state of carbon is +2. <br/> HCOOH <br/> 1+X+(-2)+(-2)+1=0 <br/> 2+X-4=0 <br/> X=4-2 <br/> X=+2</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2008>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the IUPAC nomenclature of the compound NaClO?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sodium oxochlorate(I).</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium chloro(I) oxide.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium monooxochlorate(II)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium chloro(I) monoxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The IUPAC nomenclature of the compound NaClO is Sodium oxochlorate(I). In IUPAC nomenclature, the name of a compound is determined by its composition. The name 'Sodium oxochlorate(I)' indicates that the compound contains one atom of sodium (Na), one atom of oxygen (O), and one atom of chlorine (Cl) in its +1 oxidation state.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2008>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In recharging a lead-acid accumulator,the reaction at the cathode can be represented as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2-</span>(aq)→PbSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Pb<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → PbO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + 4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pb<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In recharging lead-acid, Pb<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Pb<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> gain of electron occur at cathode, reduction takes place at the cathode</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2008>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a given quantity of electricity liberates 0.65g of Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>, what amount of Hg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>would be liberated by the same quantity of current?  <br/>  (Zn=65, Hg=201)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1.00g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.01g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.02g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.04g</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">At the cathode, we have: <br/> Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> Normally, we need  <br/> 2F → 65g <br/> x → 0.65 <br/> x = 0.02F <br/> Let us check how much mercury will be deposited by 0.02F of electricity <br/> Hg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> + 2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → Hg<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> <br/> 2F → 201g <br/> ∴ 0.02F = x <br/> x = 2.01g</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2008>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> + HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>  <br/>  The entropy change in the system above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">positive </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative </div>", "<div style=\"font-family:Cambria;font-size:17px;\">indeterminate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> + Hcl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> Reactant = 2 moles of gaseous molecules  <br/> Product = 1 mole of gaseous molecule <br/> Entropy change = 1 - 2 = -1 (negative) <br/> Entropy is a measure of the disorder or randomness of a system. In the given reaction, gaseous reactants are converted into a solid product. This leads to a decrease in the randomness of the system, hence the entropy change is negative.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2008>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reactions is endothermic?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → Ca(OH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + H2O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> → CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> → NaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water Gas is a mixture of carbon monoxide and hydrogen produced from synthesis gas.H2O + C --> H2 + CO (H=+131KJ/mol) <br/> An Endothermic process is any process which requires or absorbs thermal energy from its surroundings, usually in the form of heat.in Endothermic reaction ∆H is positive. <br/> Therefore it is Endothermic. <br/> </div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2008>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A catalyst speed up the rate of a chemical reaction by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">taking part in the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the activation energy of the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lowering the activation energy of the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the heat content</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A catalyst speeds up the rate of a chemical reaction by lowering the activation energy of the reaction. The activation energy is the minimum energy required for a reaction to occur. By lowering this energy, a catalyst allows more molecules to have the necessary energy to react, thus increasing the rate of the reaction.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2008>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a reaction usually decreases with a decrease in the concentration of reactants because</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">kinetic energy decreases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">speed increases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reactants collision decreases</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a reaction is directly proportional to the concentration of the reactants. This is because a higher concentration of reactants leads to more frequent collisions between the reactant molecules, increasing the chance of a successful reaction. Therefore, if the concentration of reactants decreases, the frequency of these collisions and hence the rate of the reaction also decreases.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2008>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>⇔ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/> In the reaction above, the equilibrium constant is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">aA<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + bB<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ≒ cC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + dD<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(eq)</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(D)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">d</span>(C)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">c</span><hr size=\"1\" />(A)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">a</span>(B)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">b</span></td><td style=\"text-align:center;\">-------------</td><td style=\"text-align:center;\">*</td></tr></table></div> <br/> Hence: N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(g)</span> ⇌ 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">k<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">eq</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></td></tr></table></div></div>", "topic": "CHEMICAL EQUILIBRA : REVERSIBLE REACTIONS"}, {"id": "objective>Chemistry>2008>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The substance that is used in the steel industry for the removal of carbon, sulphur and phosphorus impurities from pig iron is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen is used in the steel industry for the removal of carbon, sulphur and phosphorus impurities from pig iron. This process is known as oxygen refining. Oxygen reacts with these impurities to form gases such as carbon dioxide and sulfur dioxide, which are then removed.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2008>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds of trioxonitrate(V) will decompose to give dinitrogen(I) oxide and water when heated?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaNO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cu(NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonium nitrate (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) decomposes to give dinitrogen(I) oxide and water when heated. The reaction is: NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. The other compounds do not decompose in this way.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2008>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer the question that follows  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The gas that can be used to demonstrate the experiment is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen(II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dinitrogen(I) oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that can be used to demonstrate the experiment is hydrogen chloride.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2008>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer the question that follows  <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The colour of the fountain water is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange</div>", "<div style=\"font-family:Cambria;font-size:17px;\">red </div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The colour of the fountain water is red and not other colours.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2008>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a solution of ammonium trioxocarbonate(IV) is added to a solution of an unknown salt, a white precipitate which is soluble in dilute hydrochloric acid but insoluble in ethanoic acid is formed. This indicates the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The white precipitate that is soluble in dilute hydrochloric acid but insoluble in ethanoic acid indicates the presence of calcium ions (Ca<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>). This is because calcium carbonate, which is formed when calcium ions react with carbonate ions, is soluble in hydrochloric acid but insoluble in ethanoic acid.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2008>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Lead is used for making bullets and lead shots because of its</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Resistance to corrosion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Low melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High density </div>", "<div style=\"font-family:Cambria;font-size:17px;\">flexibility</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Lead is used for making bullets and lead shots because of its high density. The high density of lead gives bullets and lead shots their necessary weight and momentum. While lead does have a relatively low melting point and some resistance to corrosion, these are not the primary reasons it is used for bullets and lead shots.</div>", "topic": "METALS AND THEIR COMPOUNDS : LEAD"}, {"id": "objective>Chemistry>2008>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gives a precipitate when treated with NaOH solution?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COONa</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium chloride (AlCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) gives a precipitate when treated with NaOH solution. This is because aluminium ions react with hydroxide ions to form aluminium hydroxide, which is a white precipitate. The other compounds do not form precipitates with NaOH.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2008>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most common ores of iron include</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">haematite, malachite and limonite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chalcocite, calamine and bornite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetite, haematite and limonite</div>", "<div style=\"font-family:Cambria;font-size:17px;\">malachite, chalcocite and bornite</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most common ores of iron are magnetite, haematite, and limonite. Haematite is iron(III) oxide, Fe2O3, magnetite is iron(II,III) oxide, Fe3O4, and limonite is a mixture of hydrated iron(III) oxides and iron(III) hydroxides. </div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2008>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The type of isomerism shown by cis- and trans-isomers is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">optical isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">positional isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">functional isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">geometrical isomerism</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cis- and trans- isomers exhibit geometrical isomerism. Geometrical isomerism is a form of stereoisomerism. It is the arrangement of atoms or groups of atoms in molecules and polyatomic ions when there is restricted rotation because of the presence of a double bond or a ring structure. </div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2008>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the silver mirror test is positive, it indicates the presence of an</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkyne </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanone </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The silver mirror test is a qualitative test used to differentiate an aldehyde from a ketone. It relies on the fact that aldehydes are readily oxidized (they are reducing agents), while ketones are not. If the test is positive, a silver mirror will appear on the inside of the test tube, indicating the presence of an aldehyde. </div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2008>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The IUPAC nomenclature for the structure above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2,3-dichloro-4,4,5-trimethylpent-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4,5-dichloro-2,3-dimethylhex-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,3-dichloro-4,4-dimethylhex-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,3-dichloro-2,2-dimethylhex-2-ene</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">IUPAC nomenclature of compound is the longest carbonchain is hex-2-ene, ,the chlorine is attached to the position 2 and 3, while the methyl is attached to the position 4 and 4 . <br/>  <br/> The longest carbon chain is hex-2-ene, ,the chlorine is attached to the position 2 and 3, while the two methyl groups are attached to the position 4 </div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2008>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If glucose is heated with concentrated tetraoxosulphate(VI) acid, it will be dehydrated to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When glucose is heated with concentrated tetraoxosulphate(VI) acid, it will be dehydrated to carbon. The concentrated tetraoxosulphate(VI) acid removes elements of water (H2O) from glucose and leaves a residue of carbon. </div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2008>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A hydrocarbon X with a molar mass of 26 consists of 92.3% carbon. What is its molecular formula?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that: A hydrocarbon has only carbon and hydrogen, it implies that the percentage composition of carbon and hydrogen will add up to 100% <br/> ∴ % carbon + % hydrogen = 100%  <br/> 92.3 + % hydrogen = 100 <br/> % hydrogen = 7.7% <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Carbon(c)</td><td style=\"border:1px solid black;text-align:center;\">Hydrogen (H)</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">% comp</td><td style=\"border:1px solid black;text-align:center;\">92.3</td><td style=\"border:1px solid black;text-align:center;\">7.7</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Mass</td><td style=\"border:1px solid black;text-align:center;\">92.3</td><td style=\"border:1px solid black;text-align:center;\">7.7</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">no of moles</td><td style=\"border:1px solid black;text-align:center;\"> 92.3/12</td><td style=\"border:1px solid black;text-align:center;\">7.7/1</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">7.7</td><td style=\"border:1px solid black;text-align:center;\">7.7</td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">1</td><td style=\"border:1px solid black;text-align:center;\">1</td></tr></table></div>  <br/> Emperical formula = CH <br/> Recall: (EF)n = MF ------------- (i) <br/> (Emperical mass)n = Molecular mass ----------- (ii) <br/> (12 + 1)n = 26 <br/> 13n = 26 <br/> n = 13 <br/> sub. for n = 2 in (i) <br/> (EF)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = MF <br/> MF = (CH)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> </div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2008>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A red precipitate of copper(I) carbide is formed when ammonium solution of copper(I) chloride is introduced into</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=CH–CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>–CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>–CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>–C≡CH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>–CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>–CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>–C≡C – CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper(I) carbide is formed when an ammonium solution of copper(I) chloride is introduced into an alkyne. The alkyne in the options is CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>–CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>–C≡CH, which is option 2. Alkynes are hydrocarbons that contain a triple bond.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2008>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Reduction of nitroalkanes, nitrites and amides is a route for the preparation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amines </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkenes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polymers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">detergents</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reduction of nitroalkanes, nitrites, and amides is a route for the preparation of amines. Amines are organic compounds and functional groups that contain a basic nitrogen atom with a lone pair. They are derived from ammonia (NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) by replacement of one or more hydrogen atoms by organic groups.</div>", "topic": "ORGANIC COMPOUNDS : AMINES"}, {"id": "objective>Chemistry>2008>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The major product of the dehydration of the above compound is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">  The major product of the dehydration of the above compound is <img src=\"2008/s30.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2008>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Reduction of alkanones with LiAlH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> produces</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">primary alkanols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary alkanols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary alkanols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polyhydric alkanols</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reduction of alkanones with LiAlH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> produces secondary alkanols. Alkanones are a type of ketone, and when they are reduced, they form secondary alcohols. This is because the carbonyl carbon in the ketone becomes a new chiral center in the alcohol.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2008>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The product obtained when a mixture of benzene vapour and hydrogen are passed over a nickel catalyst at 180°C is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cyclohexane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cyclopentane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n-hexane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">n-pentane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The product obtained when a mixture of benzene vapour and hydrogen are passed over a nickel catalyst at 180°C is cyclohexane. This is a hydrogenation reaction, where the benzene ring is fully saturated with hydrogen to form cyclohexane.</div>", "topic": "ORGANIC COMPOUNDS : AROMATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2008>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Polyvinyl chloride is used in the production of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alloy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pipes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ceramics</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Polyvinyl chloride, also known as PVC, is used in the production of pipes. PVC is a type of plastic that is durable, cost-effective, and easy to assemble, making it ideal for use in pipe construction.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2008>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Detergents are manufactured with straight hydrocarbon chains so as to make them</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">soluble </div>", "<div style=\"font-family:Cambria;font-size:17px;\">biodegradable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cheaper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">foamy</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Detergents are manufactured with straight hydrocarbon chains to make them biodegradable. Biodegradability refers to the ability of a substance to be broken down by biological organisms, especially bacteria. Straight chain hydrocarbons are more susceptible to bacterial action, hence, they are more biodegradable.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}];
